object CloudApi {
    private const val BASE_URL = "https://api.example.com"
    
    fun getDevicesUrl() = "$BASE_URL/devices"
    fun getDeviceUrl(deviceId: String) = "$BASE_URL/devices/$deviceId"
    fun getUserUrl() = "$BASE_URL/user"
}

object LocalDeviceApi {
    fun getDeviceStatusUrl(ipAddress: String) = "http://$ipAddress/status"
    fun getDeviceControlUrl(ipAddress: String) = "http://$ipAddress/control"
    fun getDeviceConfigUrl(ipAddress: String) = "http://$ipAddress/config"
}

class IoTRepository(context: Context) {
    private val httpClient = IoTHttpClient(context)

    suspend fun getCloudDevices(): ApiResult<String> {
        return httpClient.get(CloudApi.getDevicesUrl())
    }

    suspend fun getCloudDevice(deviceId: String): ApiResult<String> {
        return httpClient.get(CloudApi.getDeviceUrl(deviceId))
    }

    suspend fun updateCloudDevice(deviceId: String, data: String): ApiResult<String> {
        return httpClient.put(CloudApi.getDeviceUrl(deviceId), data)
    }

    suspend fun getLocalDeviceStatus(ipAddress: String): ApiResult<String> {
        return httpClient.get(LocalDeviceApi.getDeviceStatusUrl(ipAddress))
    }

    suspend fun controlLocalDevice(ipAddress: String, command: String): ApiResult<String> {
        return httpClient.post(LocalDeviceApi.getDeviceControlUrl(ipAddress), command)
    }

    suspend fun getLocalDeviceConfig(ipAddress: String): ApiResult<String> {
        return httpClient.get(LocalDeviceApi.getDeviceConfigUrl(ipAddress))
    }

    suspend fun updateLocalDeviceConfig(ipAddress: String, config: String): ApiResult<String> {
        return httpClient.put(LocalDeviceApi.getDeviceConfigUrl(ipAddress), config)
    }
}